import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Validate input length before copying
        if (input.length() > 10) {
            System.out.println("Input length exceeds buffer size. Aborting.");
            return;
        }

        byte[] buffer = new byte[10];

        // Copy user input into buffer after proper validation
        System.arraycopy(input.getBytes(), 0, buffer, 0, input.length());

        System.out.println("Input successfully copied into buffer.");
    }
}

